// Store sounds as base64 data URIs to keep the app self-contained.
// The key is the sound name, and the value is the data URI.
const sounds: { [key: string]: string } = {
  emergencyMeeting: 'data:audio/mpeg;base64,',
  sabotageBeep: 'data:audio/wav;base64,',
  startGame: 'data:audio/mpeg;base64,'
};

// Use a single AudioContext for the application.
let audioContext: AudioContext;
const getAudioContext = () => {
    if (!audioContext) {
        audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    return audioContext;
};

// Cache for decoded audio buffers to avoid re-decoding.
const audioBuffers: { [key: string]: AudioBuffer } = {};

async function decodeAudioDataForPlay(dataUri: string, context: AudioContext): Promise<AudioBuffer> {
  if (audioBuffers[dataUri]) {
    return audioBuffers[dataUri];
  }
  const response = await fetch(dataUri);
  const arrayBuffer = await response.arrayBuffer();
  const audioBuffer = await context.decodeAudioData(arrayBuffer);
  audioBuffers[dataUri] = audioBuffer;
  return audioBuffer;
}

export const playSound = async (soundName: string) => {
  const context = getAudioContext();
  // Resume context on user interaction if it's suspended.
  if (context.state === 'suspended') {
    await context.resume();
  }
  
  const dataUri = sounds[soundName];
  if (dataUri && dataUri.split(',')[1]) {
    try {
      const audioBuffer = await decodeAudioDataForPlay(dataUri, context);
      const source = context.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(context.destination);
      source.start(0);
    } catch (error) {
      console.error(`Error playing sound '${soundName}':`, error);
    }
  }
};